// Parse Google Calendar FreeBusy response and find available slots
const calendarResponse = $input.first().json;
const webhookInput = $('Webhook').first().json.body;

// Get busy periods from response
const calendarId = webhookInput.calendar_id || 'primary';
const calendars = calendarResponse.calendars || {};
const busyPeriods = calendars[calendarId]?.busy || [];

// Define business hours for slot generation
const slotDuration = webhookInput.duration_minutes || 30;
const businessStart = webhookInput.business_start_hour || 9; // 9 AM
const businessEnd = webhookInput.business_end_hour || 17;     // 5 PM

const startDate = new Date(webhookInput.start_date || new Date().toISOString());
const endDate = new Date(webhookInput.end_date || new Date(Date.now() + 7*24*60*60*1000).toISOString());

// Generate available slots (business hours, skip weekends)
const availableSlots = [];
const current = new Date(startDate);
current.setMinutes(0, 0, 0);

while (current < endDate && availableSlots.length < 20) {
  const dayOfWeek = current.getDay();
  const hour = current.getHours();

  // Skip weekends (0=Sun, 6=Sat)
  if (dayOfWeek === 0 || dayOfWeek === 6) {
    current.setDate(current.getDate() + 1);
    current.setHours(businessStart, 0, 0, 0);
    continue;
  }

  // Skip outside business hours
  if (hour < businessStart) {
    current.setHours(businessStart, 0, 0, 0);
    continue;
  }
  if (hour >= businessEnd) {
    current.setDate(current.getDate() + 1);
    current.setHours(businessStart, 0, 0, 0);
    continue;
  }

  const slotEnd = new Date(current.getTime() + slotDuration * 60000);

  // Check if slot overlaps any busy period
  const isBusy = busyPeriods.some(busy => {
    const busyStart = new Date(busy.start);
    const busyEnd = new Date(busy.end);
    return current < busyEnd && slotEnd > busyStart;
  });

  if (!isBusy) {
    availableSlots.push({
      start: current.toISOString(),
      end: slotEnd.toISOString(),
      date: current.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' }),
      time: current.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', hour12: true, timeZone: 'America/New_York' })
    });
  }

  current.setMinutes(current.getMinutes() + slotDuration);
}

return [{
  json: {
    success: true,
    available_slots: availableSlots,
    total_slots: availableSlots.length,
    busy_periods: busyPeriods.length,
    search_range: {
      start: startDate.toISOString(),
      end: endDate.toISOString()
    },
    slot_duration_minutes: slotDuration,
    checked_at: new Date().toISOString()
  }
}];
